<content><![CDATA[
import React, { useState, useEffect } from 'react';
import { User, Lock, ArrowRight, Frown, Info, Smartphone, CreditCard, Shield, Briefcase, HelpCircle, RefreshCw } from 'lucide-react';
import { Staff } from '../types';

interface LoginProps {
  staffList: Staff[];
  onLogin: (userId: string, role: 'ADMIN' | 'USER') => void;
}

const Login: React.FC<LoginProps> = ({ staffList, onLogin }) => {
  // Login Mode State
  const [loginMode, setLoginMode] = useState<'STAFF' | 'ADMIN'>('STAFF');

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    idCardSuffix: '', // Last 6 digits
    adminUser: '',
    adminPass: '',
    captchaInput: ''
  });

  const [captchaCode, setCaptchaCode] = useState('');
  const [error, setError] = useState('');

  // Status Feedback View
  const [loginStatusView, setLoginStatusView] = useState<'NORMAL' | 'REJECTED' | 'WAITING_GROUP'>('NORMAL');

  // Generate Captcha
  const generateCaptcha = () => {
    const chars = '23456789ABCDEFGHJKLMNPQRSTUVWXYZ';
    let result = '';
    for (let i = 0; i < 4; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setCaptchaCode(result);
  };

  useEffect(() => {
    generateCaptcha();
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoginStatusView('NORMAL');

    // --- ADMIN LOGIN LOGIC ---
    if (loginMode === 'ADMIN') {
      // Verify Captcha only for Admin
      if (formData.captchaInput.toUpperCase() !== captchaCode) {
         setError('验证码错误，请重新输入');
         generateCaptcha();
         setFormData({...formData, captchaInput: ''});
         return;
      }

      if (formData.adminUser === 'admin' && formData.adminPass === 'password') {
        onLogin('admin', 'ADMIN');
      } else {
        setError('管理员账号或密码错误');
        generateCaptcha();
      }
      return;
    }

    // --- STAFF/OUTSOURCED LOGIN LOGIC ---
    const { name, phone, idCardSuffix } = formData;

    if (!name || !phone || !idCardSuffix) {
       setError('请填写完整信息');
       return;
    }

    // Find staff by Name and Phone first
    const staff = staffList.find(s => s.name === name && s.phone === phone);

    if (staff) {
      // Check ID Card Suffix (Last 6 digits)
      const actualIdSuffix = staff.idCard ? staff.idCard.slice(-6) : '';

      if (actualIdSuffix !== idCardSuffix) {
         setError('身份验证失败：身份证后6位不匹配');
         return;
      }

      // Logic Gate for Staff Status
      if (staff.status === 'REJECTED') {
        setLoginStatusView('REJECTED');
        return;
      }

      if (staff.status === 'INTERVIEWED' && staff.roles.length === 0) {
        setLoginStatusView('WAITING_GROUP');
        return;
      }

      // Successful Login
      onLogin(staff.id, 'USER');
      return;
    } 

    // If no match found
    setError('登录失败：未找到该人员信息或手机号错误');
  };

  const resetForm = () => {
    setLoginStatusView('NORMAL');
    setFormData({ name: '', phone: '', idCardSuffix: '', adminUser: '', adminPass: '', captchaInput: '' });
    generateCaptcha();
    setError('');
  };

  // --- Render Status Screens (Rejected / Waiting) ---
  if (loginStatusView === 'REJECTED') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 px-4">
        <div className="w-full max-w-md bg-white rounded-3xl shadow-xl p-10 text-center animate-fade-in border border-gray-100">
           <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6">
             <Frown size={40} className="text-red-500" />
           </div>
           <h2 className="text-2xl font-bold text-gray-800 mb-3">面试未通过</h2>
           <p className="text-gray-500 mb-8 leading-relaxed">
             很遗憾，经综合评估，您暂时不符合该职位的录用标准。<br/>
             感谢您的参与，祝您下次努力加油！
           </p>
           <button onClick={resetForm} className="w-full py-3 border border-gray-200 rounded-xl text-gray-600 font-medium hover:bg-gray-50 transition-colors">
             返回登录
           </button>
        </div>
      </div>
    );
  }

  if (loginStatusView === 'WAITING_GROUP') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 px-4">
        <div className="w-full max-w-md bg-white rounded-3xl shadow-xl p-10 text-center animate-fade-in border border-gray-100">
           <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-6">
             <Info size={40} className="text-blue-600" />
           </div>
           <h2 className="text-2xl font-bold text-gray-800 mb-3">面试已通过</h2>
           <p className="text-gray-500 mb-8 leading-relaxed">
             恭喜您通过面试！<br/>
             您的入职流程正在处理中，请等待管理员为您分配组别后，再登录系统进行考勤打卡。
           </p>
           <button onClick={resetForm} className="w-full py-3 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 shadow-lg shadow-blue-200">
             知道了
           </button>
        </div>
      </div>
    );
  }

  // --- Main Login Form ---
  return (
    <div className="min-h-screen flex bg-white font-sans overflow-hidden">

      {/* Left Side: Hero Image & Branding */}
      <div className="hidden lg:flex w-1/2 bg-slate-900 relative items-center justify-center overflow-hidden">
        {/* Abstract Background Image */}
        <div className="absolute inset-0 z-0">
           <img 
             src="https://images.unsplash.com/photo-1497215728101-856f4ea42174?q=80&w=2000&auto=format&fit=crop" 
             alt="Office" 
             className="w-full h-full object-cover opacity-40 mix-blend-overlay"
           />
           <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-slate-900/80 to-indigo-900/50"></div>
        </div>

        <div className="relative z-10 p-12 max-w-2xl text-white">
           <div className="w-12 h-12 bg-indigo-500 rounded-xl flex items-center justify-center mb-8 shadow-lg shadow-indigo-500/30">
              <Shield size={24} className="text-white" />
           </div>
           <h1 className="text-5xl font-bold mb-6 tracking-tight leading-tight">
             WorkPulse <br/> 
             <span className="text-indigo-400">智能人力资源系统</span>
           </h1>
           <p className="text-slate-300 text-lg leading-relaxed mb-8 max-w-lg">
             一站式管理考勤、面试、入职与组织架构。高效协同，让团队管理更轻松。
           </p>

           <div className="flex gap-4">
              <div className="flex items-center gap-2 bg-white/10 backdrop-blur-md px-4 py-2 rounded-lg border border-white/10">
                 <div className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></div>
                 <span className="text-sm font-medium">系统运行正常</span>
              </div>
              <div className="flex items-center gap-2 bg-white/10 backdrop-blur-md px-4 py-2 rounded-lg border border-white/10">
                 <span className="text-sm font-medium">V 2.5.0 Pro</span>
              </div>
           </div>
        </div>
      </div>

      {/* Right Side: Login Form */}
      <div className="w-full lg:w-1/2 flex items-center justify-center p-6 bg-white relative">
        <div className="w-full max-w-md space-y-8 animate-fade-in">

          <div className="text-center lg:text-left">
            <h2 className="text-3xl font-extrabold text-gray-900">欢迎回来</h2>
            <p className="mt-2 text-gray-500">请选择您的身份登录系统</p>
          </div>

          {/* Toggle Switch */}
          <div className="bg-gray-100 p-1.5 rounded-xl flex relative">
             {/* Slider Animation Background */}
             <div 
               className={`absolute top-1.5 bottom-1.5 w-[calc(50%-6px)] bg-white rounded-lg shadow-sm transition-all duration-300 ease-out ${loginMode === 'STAFF' ? 'left-1.5' : 'left-[calc(50%+3px)]'}`}
             ></div>

             <button 
               onClick={() => { setLoginMode('STAFF'); setError(''); generateCaptcha(); setFormData({...formData, captchaInput: ''}) }}
               className={`flex-1 relative z-10 py-2.5 text-sm font-bold rounded-lg flex items-center justify-center gap-2 transition-colors ${loginMode === 'STAFF' ? 'text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
                <Briefcase size={16} /> STAFF/编外
             </button>
             <button 
               onClick={() => { setLoginMode('ADMIN'); setError(''); generateCaptcha(); setFormData({...formData, captchaInput: ''}) }}
               className={`flex-1 relative z-10 py-2.5 text-sm font-bold rounded-lg flex items-center justify-center gap-2 transition-colors ${loginMode === 'ADMIN' ? 'text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
                <Shield size={16} /> 管理员
             </button>
          </div>

          <form onSubmit={handleLogin} className="space-y-5 min-h-[380px]">

             {loginMode === 'STAFF' ? (
                <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                   {/* Name */}
                   <div className="group">
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">姓名</label>
                      <div className="relative">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                           <User size={18} />
                        </div>
                        <input
                          type="text"
                          required
                          placeholder="请输入您的真实姓名"
                          className="w-full pl-11 pr-4 py-3.5 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-100 focus:border-indigo-500 focus:bg-white outline-none transition-all font-medium text-gray-800 placeholder-gray-400"
                          value={formData.name}
                          onChange={e => setFormData({...formData, name: e.target.value})}
                        />
                      </div>
                   </div>

                   {/* Phone */}
                   <div className="group">
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">手机号码</label>
                      <div className="relative">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                           <Smartphone size={18} />
                        </div>
                        <input
                          type="tel"
                          required
                          placeholder="请输入手机号码"
                          className="w-full pl-11 pr-4 py-3.5 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-100 focus:border-indigo-500 focus:bg-white outline-none transition-all font-medium text-gray-800 placeholder-gray-400"
                          value={formData.phone}
                          onChange={e => setFormData({...formData, phone: e.target.value})}
                        />
                      </div>
                   </div>

                   {/* ID Card */}
                   <div className="group">
                      <div className="flex justify-between items-center mb-1.5 ml-1">
                         <label className="block text-xs font-bold text-gray-500 uppercase">身份证后6位</label>
                         <div className="group/tooltip relative">
                           <HelpCircle size={14} className="text-gray-400 cursor-help" />
                           <div className="absolute bottom-full right-0 mb-2 w-48 bg-gray-800 text-white text-xs p-2 rounded shadow-lg opacity-0 group-hover/tooltip:opacity-100 transition-opacity pointer-events-none">
                              作为身份验证凭证，请输入您身份证号码的最后6位（含字母）。
                           </div>
                         </div>
                      </div>
                      <div className="relative">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                           <CreditCard size={18} />
                        </div>
                        <input
                          type="text"
                          required
                          maxLength={6}
                          placeholder="例如: 12345X"
                          className="w-full pl-11 pr-4 py-3.5 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-100 focus:border-indigo-500 focus:bg-white outline-none transition-all font-medium text-gray-800 placeholder-gray-400 tracking-wider uppercase"
                          value={formData.idCardSuffix}
                          onChange={e => setFormData({...formData, idCardSuffix: e.target.value})}
                        />
                      </div>
                   </div>
                </div>
             ) : (
                <div className="space-y-4 animate-in fade-in slide-in-from-left-4 duration-300">
                   {/* Admin User */}
                   <div className="group">
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">管理员账号</label>
                      <div className="relative">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                           <User size={18} />
                        </div>
                        <input
                          type="text"
                          required
                          placeholder="admin"
                          className="w-full pl-11 pr-4 py-3.5 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-100 focus:border-indigo-500 focus:bg-white outline-none transition-all font-medium text-gray-800 placeholder-gray-400"
                          value={formData.adminUser}
                          onChange={e => setFormData({...formData, adminUser: e.target.value})}
                        />
                      </div>
                   </div>

                   {/* Admin Pass */}
                   <div className="group">
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">密码</label>
                      <div className="relative">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                           <Lock size={18} />
                        </div>
                        <input
                          type="password"
                          required
                          placeholder="password"
                          className="w-full pl-11 pr-4 py-3.5 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-100 focus:border-indigo-500 focus:bg-white outline-none transition-all font-medium text-gray-800 placeholder-gray-400"
                          value={formData.adminPass}
                          onChange={e => setFormData({...formData, adminPass: e.target.value})}
                        />
                      </div>
                   </div>

                   {/* Captcha Field - Only for Admin */}
                   <div className="group animate-in fade-in duration-500">
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">验证码</label>
                      <div className="flex gap-3">
                         <div className="relative flex-1">
                            <input
                              type="text"
                              required
                              maxLength={4}
                              placeholder="请输入右侧字符"
                              className="w-full px-4 py-3.5 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-100 focus:border-indigo-500 focus:bg-white outline-none transition-all font-medium text-gray-800 placeholder-gray-400 uppercase tracking-widest text-center"
                              value={formData.captchaInput}
                              onChange={e => setFormData({...formData, captchaInput: e.target.value})}
                            />
                         </div>
                         <div 
                           onClick={generateCaptcha}
                           className="w-32 bg-gray-100 border border-gray-200 rounded-xl flex items-center justify-center cursor-pointer select-none relative overflow-hidden group/captcha hover:border-gray-300 transition-all"
                           title="点击刷新验证码"
                         >
                            <div className="absolute inset-0 opacity-10 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-gray-500 via-gray-300 to-transparent"></div>
                            <span className="text-xl font-mono font-black text-gray-600 tracking-[0.2em] relative z-10 transform -rotate-2 select-none" style={{textShadow: '2px 2px 0px rgba(0,0,0,0.1)'}}>
                               {captchaCode}
                            </span>
                            {/* Noise lines */}
                            <div className="absolute top-1/2 left-0 w-full h-px bg-gray-300 transform rotate-12"></div>
                            <div className="absolute top-1/3 left-0 w-full h-px bg-gray-300 transform -rotate-12"></div>

                            <div className="absolute top-1 right-1 text-gray-400 opacity-0 group-hover/captcha:opacity-100 transition-opacity">
                               <RefreshCw size={10} />
                            </div>
                         </div>
                      </div>
                   </div>
                </div>
             )}

             {error && (
               <div className="bg-red-50 text-red-600 text-sm p-3.5 rounded-xl border border-red-100 flex items-center gap-2 animate-shake">
                 <div className="w-1.5 h-1.5 bg-red-600 rounded-full shrink-0" />
                 {error}
               </div>
             )}

             <button
               type="submit"
               className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 shadow-xl shadow-indigo-200 hover:-translate-y-0.5 active:scale-95 duration-200 mt-2"
             >
               {loginMode === 'STAFF' ? '验证并登录' : '管理员登录'} <ArrowRight size={20} />
             </button>
          </form>

          {/* Test Accounts Hint */}
          <div className="mt-8 pt-6 border-t border-gray-100">
             <div className="text-xs text-center text-gray-400 mb-3">开发环境测试账号</div>
             <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
                <div className="p-2 bg-gray-50 border border-gray-100 rounded text-[10px] text-gray-600 cursor-pointer hover:bg-gray-100" onClick={() => { setLoginMode('STAFF'); setFormData({...formData, name: '已签到员工', phone: '13800000001', idCardSuffix: '888888'}) }}>
                   <p className="font-bold">员工 (已签到)</p>
                   <p>ID: 888888</p>
                </div>
                <div className="p-2 bg-gray-50 border border-gray-100 rounded text-[10px] text-gray-600 cursor-pointer hover:bg-gray-100" onClick={() => { setLoginMode('STAFF'); setFormData({...formData, name: '赵云(组长)', phone: '13800000004', idCardSuffix: '111111'}) }}>
                   <p className="font-bold">组长 (赵云)</p>
                   <p>ID: 111111</p>
                </div>
                <div className="p-2 bg-gray-50 border border-gray-100 rounded text-[10px] text-gray-600 cursor-pointer hover:bg-gray-100" onClick={() => { setLoginMode('STAFF'); setFormData({...formData, name: '孙尚香(淘汰)', phone: '13800000006', idCardSuffix: '000000'}) }}>
                   <p className="font-bold">被淘汰</p>
                   <p>ID: 000000</p>
                </div>
                <div className="p-2 bg-gray-50 border border-gray-100 rounded text-[10px] text-gray-600 cursor-pointer hover:bg-gray-100" onClick={() => { setLoginMode('STAFF'); setFormData({...formData, name: '诸葛亮(待分配)', phone: '13800000005', idCardSuffix: '222222'}) }}>
                   <p className="font-bold">待分租</p>
                   <p>ID: 222222</p>
                </div>
                <div className="p-2 bg-gray-50 border border-gray-100 rounded text-[10px] text-gray-600 cursor-pointer hover:bg-gray-100 col-span-2 md:col-span-1" onClick={() => { setLoginMode('ADMIN'); setFormData({...formData, adminUser: 'admin', adminPass: 'password'}) }}>
                   <p className="font-bold">管理员</p>
                   <p>pass: password</p>
                </div>
             </div>
          </div>

        </div>
      </div>
    </div>
  );
};

export default Login;
]]></content>
