<description>Redesign Login page with a vibrant, youthful aesthetic (Gen Z style). Use abstract gradients, soft UI for inputs, and modern typography while keeping the exact functionality and split-screen layout.</description>
<content><![CDATA[
import React, { useState, useEffect } from 'react';
import { User, Lock, ArrowRight, Frown, Info, Smartphone, CreditCard, Shield, Briefcase, HelpCircle, RefreshCw, Sparkles, Zap, AlertCircle } from 'lucide-react';
import { Staff } from '../types';

interface LoginProps {
  staffList: Staff[];
  onLogin: (userId: string, role: 'ADMIN' | 'USER') => void;
}

const Login: React.FC<LoginProps> = ({ staffList, onLogin }) => {
  // Login Mode State
  const [loginMode, setLoginMode] = useState<'STAFF' | 'ADMIN'>('STAFF');

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    idCardSuffix: '', // Last 6 digits
    adminUser: '',
    adminPass: '',
    captchaInput: ''
  });

  const [captchaCode, setCaptchaCode] = useState('');
  const [error, setError] = useState('');

  // Status Feedback View
  const [loginStatusView, setLoginStatusView] = useState<'NORMAL' | 'REJECTED' | 'WAITING_GROUP'>('NORMAL');

  // Generate Captcha
  const generateCaptcha = () => {
    const chars = '23456789ABCDEFGHJKLMNPQRSTUVWXYZ';
    let result = '';
    for (let i = 0; i < 4; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setCaptchaCode(result);
  };

  useEffect(() => {
    generateCaptcha();
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoginStatusView('NORMAL');

    // --- ADMIN LOGIN LOGIC ---
    if (loginMode === 'ADMIN') {
      // Verify Captcha only for Admin
      if (formData.captchaInput.toUpperCase() !== captchaCode) {
         setError('验证码错误，请点击图片刷新');
         generateCaptcha();
         setFormData({...formData, captchaInput: ''});
         return;
      }

      if (formData.adminUser === 'admin' && formData.adminPass === 'password') {
        onLogin('admin', 'ADMIN');
      } else {
        setError('管理员账号或密码错误');
        generateCaptcha();
      }
      return;
    }

    // --- STAFF/OUTSOURCED LOGIN LOGIC ---
    const { name, phone, idCardSuffix } = formData;

    if (!name || !phone || !idCardSuffix) {
       setError('请填写完整信息');
       return;
    }

    // Find staff by Name and Phone first
    const staff = staffList.find(s => s.name === name && s.phone === phone);

    if (staff) {
      // Check ID Card Suffix (Last 6 digits)
      const actualIdSuffix = staff.idCard ? staff.idCard.slice(-6) : '';

      if (actualIdSuffix !== idCardSuffix) {
         setError('身份验证失败：身份证后6位不匹配');
         return;
      }

      // Logic Gate for Staff Status
      if (staff.status === 'REJECTED') {
        setLoginStatusView('REJECTED');
        return;
      }

      if (staff.status === 'INTERVIEWED' && staff.roles.length === 0) {
        setLoginStatusView('WAITING_GROUP');
        return;
      }

      // Successful Login
      onLogin(staff.id, 'USER');
      return;
    } 

    // If no match found
    setError('登录失败：未找到该人员信息或手机号错误');
  };

  const resetForm = () => {
    setLoginStatusView('NORMAL');
    setFormData({ name: '', phone: '', idCardSuffix: '', adminUser: '', adminPass: '', captchaInput: '' });
    generateCaptcha();
    setError('');
  };

  // --- Render Status Screens (Rejected / Waiting) ---
  if (loginStatusView === 'REJECTED') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#F8FAFC] px-4 font-sans">
        <div className="w-full max-w-md bg-white rounded-[2rem] shadow-2xl p-10 text-center animate-fade-in border border-gray-100 relative overflow-hidden">
           <div className="absolute top-0 left-0 w-full h-2 bg-red-500"></div>
           <div className="w-24 h-24 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
             <Frown size={48} className="text-red-500" />
           </div>
           <h2 className="text-2xl font-black text-gray-800 mb-3 tracking-tight">面试未通过</h2>
           <p className="text-gray-500 mb-8 leading-relaxed text-sm">
             很遗憾，经综合评估，您暂时不符合该职位的录用标准。<br/>
             感谢您的参与，祝您下次努力加油！
           </p>
           <button onClick={resetForm} className="w-full py-3.5 bg-gray-100 hover:bg-gray-200 rounded-xl text-gray-700 font-bold transition-all">
             返回登录
           </button>
        </div>
      </div>
    );
  }

  if (loginStatusView === 'WAITING_GROUP') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#F8FAFC] px-4 font-sans">
        <div className="w-full max-w-md bg-white rounded-[2rem] shadow-2xl p-10 text-center animate-fade-in border border-gray-100 relative overflow-hidden">
           <div className="absolute top-0 left-0 w-full h-2 bg-blue-500"></div>
           <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
             <Info size={48} className="text-blue-600" />
           </div>
           <h2 className="text-2xl font-black text-gray-800 mb-3 tracking-tight">面试已通过</h2>
           <p className="text-gray-500 mb-8 leading-relaxed text-sm">
             恭喜您通过面试！<br/>
             您的入职流程正在处理中，请等待管理员为您分配组别后，再登录系统。
           </p>
           <button onClick={resetForm} className="w-full py-3.5 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 shadow-lg shadow-blue-200 transition-all">
             知道了
           </button>
        </div>
      </div>
    );
  }

  // --- Main Login Form ---
  return (
    <div className="min-h-screen flex bg-white font-sans overflow-hidden">

      {/* Left Side: Modern Abstract Visuals */}
      <div className="hidden lg:flex w-1/2 relative items-center justify-center overflow-hidden bg-black">
        {/* Colorful Gradient Mesh Background */}
        <div className="absolute inset-0 z-0 opacity-80">
           <img 
             src="https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=2000&auto=format&fit=crop" 
             alt="Abstract Gradient" 
             className="w-full h-full object-cover"
           />
           {/* Overlay Gradient */}
           <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-black/40"></div>
           <div className="absolute inset-0 bg-black/20 backdrop-blur-[1px]"></div>
        </div>

        <div className="relative z-10 p-16 max-w-2xl text-white">
           <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-white/10 border border-white/20 backdrop-blur-md mb-8">
              <Sparkles size={14} className="text-yellow-300" />
              <span className="text-xs font-bold tracking-wide uppercase">Next Gen HR Platform</span>
           </div>

           <h1 className="text-6xl font-black mb-6 tracking-tight leading-[1.1]">
             WorkPulse <br/> 
             <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400">Future Ready.</span>
           </h1>
           <p className="text-gray-300 text-lg leading-relaxed mb-10 max-w-md font-light">
             高效协同，数据驱动。为年轻团队打造的智能人力资源与考勤管理系统。
           </p>

           {/* Stats / Trust Badges */}
           <div className="flex gap-6">
              <div className="flex flex-col">
                 <span className="text-3xl font-bold">10k+</span>
                 <span className="text-xs text-gray-400 uppercase tracking-wider">Users</span>
              </div>
              <div className="w-px bg-white/20 h-10"></div>
              <div className="flex flex-col">
                 <span className="text-3xl font-bold">99.9%</span>
                 <span className="text-xs text-gray-400 uppercase tracking-wider">Uptime</span>
              </div>
           </div>
        </div>
      </div>

      {/* Right Side: Login Form */}
      <div className="w-full lg:w-1/2 flex items-center justify-center p-6 bg-white relative">
        <div className="w-full max-w-[420px] space-y-8 animate-fade-in">

          <div className="text-center lg:text-left">
            <h2 className="text-3xl font-black text-gray-900 tracking-tight flex items-center gap-2">
               <div className="w-3 h-8 bg-indigo-600 rounded-full lg:hidden"></div> 
               欢迎回来
            </h2>
            <p className="mt-2 text-gray-500 text-sm font-medium">请选择您的身份登录 WorkPulse</p>
          </div>

          {/* Modern Toggle Switch */}
          <div className="bg-gray-100 p-1.5 rounded-2xl flex relative h-14">
             {/* Slider */}
             <div 
               className={`absolute top-1.5 bottom-1.5 w-[calc(50%-6px)] bg-white rounded-xl shadow-[0_2px_8px_rgba(0,0,0,0.08)] transition-all duration-300 ease-spring ${loginMode === 'STAFF' ? 'left-1.5' : 'left-[calc(50%+3px)]'}`}
             ></div>

             <button 
               onClick={() => { setLoginMode('STAFF'); setError(''); generateCaptcha(); setFormData({...formData, captchaInput: ''}) }}
               className={`flex-1 relative z-10 text-sm font-bold rounded-xl flex items-center justify-center gap-2 transition-colors duration-200 ${loginMode === 'STAFF' ? 'text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
                <Briefcase size={18} className={loginMode === 'STAFF' ? 'text-indigo-600' : 'text-gray-400'} /> STAFF / 编外
             </button>
             <button 
               onClick={() => { setLoginMode('ADMIN'); setError(''); generateCaptcha(); setFormData({...formData, captchaInput: ''}) }}
               className={`flex-1 relative z-10 text-sm font-bold rounded-xl flex items-center justify-center gap-2 transition-colors duration-200 ${loginMode === 'ADMIN' ? 'text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
                <Shield size={18} className={loginMode === 'ADMIN' ? 'text-indigo-600' : 'text-gray-400'} /> 管理员
             </button>
          </div>

          <form onSubmit={handleLogin} className="space-y-5">

             {loginMode === 'STAFF' ? (
                <div className="space-y-5 animate-in fade-in slide-in-from-right-4 duration-300">
                   {/* Name */}
                   <div className="space-y-1.5">
                      <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider ml-1">姓名</label>
                      <div className="relative group">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                           <User size={20} />
                        </div>
                        <input
                          type="text"
                          required
                          placeholder="您的真实姓名"
                          className="w-full pl-12 pr-4 py-4 bg-gray-50 border-2 border-transparent rounded-2xl focus:border-indigo-500 focus:bg-white outline-none transition-all font-bold text-gray-800 placeholder-gray-400 text-sm"
                          value={formData.name}
                          onChange={e => setFormData({...formData, name: e.target.value})}
                        />
                      </div>
                   </div>

                   {/* Phone */}
                   <div className="space-y-1.5">
                      <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider ml-1">手机号码</label>
                      <div className="relative group">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                           <Smartphone size={20} />
                        </div>
                        <input
                          type="tel"
                          required
                          placeholder="请输入手机号"
                          className="w-full pl-12 pr-4 py-4 bg-gray-50 border-2 border-transparent rounded-2xl focus:border-indigo-500 focus:bg-white outline-none transition-all font-bold text-gray-800 placeholder-gray-400 text-sm"
                          value={formData.phone}
                          onChange={e => setFormData({...formData, phone: e.target.value})}
                        />
                      </div>
                   </div>

                   {/* ID Card */}
                   <div className="space-y-1.5">
                      <div className="flex justify-between items-center ml-1">
                         <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider">身份证后6位</label>
                         <div className="group/tooltip relative">
                           <HelpCircle size={14} className="text-gray-300 hover:text-indigo-500 cursor-help transition-colors" />
                           <div className="absolute bottom-full right-0 mb-2 w-48 bg-gray-800 text-white text-xs p-3 rounded-xl shadow-xl opacity-0 group-hover/tooltip:opacity-100 transition-opacity pointer-events-none z-20">
                              作为身份验证凭证，请输入您身份证号码的最后6位（含字母）。
                           </div>
                         </div>
                      </div>
                      <div className="relative group">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                           <CreditCard size={20} />
                        </div>
                        <input
                          type="text"
                          required
                          maxLength={6}
                          placeholder="例如: 12345X"
                          className="w-full pl-12 pr-4 py-4 bg-gray-50 border-2 border-transparent rounded-2xl focus:border-indigo-500 focus:bg-white outline-none transition-all font-bold text-gray-800 placeholder-gray-400 text-sm tracking-widest uppercase"
                          value={formData.idCardSuffix}
                          onChange={e => setFormData({...formData, idCardSuffix: e.target.value})}
                        />
                      </div>
                   </div>
                </div>
             ) : (
                <div className="space-y-5 animate-in fade-in slide-in-from-left-4 duration-300">
                   {/* Admin User */}
                   <div className="space-y-1.5">
                      <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider ml-1">管理员账号</label>
                      <div className="relative group">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                           <User size={20} />
                        </div>
                        <input
                          type="text"
                          required
                          placeholder="admin"
                          className="w-full pl-12 pr-4 py-4 bg-gray-50 border-2 border-transparent rounded-2xl focus:border-indigo-500 focus:bg-white outline-none transition-all font-bold text-gray-800 placeholder-gray-400 text-sm"
                          value={formData.adminUser}
                          onChange={e => setFormData({...formData, adminUser: e.target.value})}
                        />
                      </div>
                   </div>

                   {/* Admin Pass */}
                   <div className="space-y-1.5">
                      <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider ml-1">密码</label>
                      <div className="relative group">
                        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                           <Lock size={20} />
                        </div>
                        <input
                          type="password"
                          required
                          placeholder="••••••••"
                          className="w-full pl-12 pr-4 py-4 bg-gray-50 border-2 border-transparent rounded-2xl focus:border-indigo-500 focus:bg-white outline-none transition-all font-bold text-gray-800 placeholder-gray-400 text-sm"
                          value={formData.adminPass}
                          onChange={e => setFormData({...formData, adminPass: e.target.value})}
                        />
                      </div>
                   </div>

                   {/* Captcha Field - Only for Admin */}
                   <div className="space-y-1.5 animate-in fade-in duration-500">
                      <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider ml-1">安全验证</label>
                      <div className="flex gap-3">
                         <div className="relative flex-1 group">
                            <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors">
                               <Shield size={20} />
                            </div>
                            <input
                              type="text"
                              required
                              maxLength={4}
                              placeholder="输入字符"
                              className="w-full pl-12 pr-4 py-4 bg-gray-50 border-2 border-transparent rounded-2xl focus:border-indigo-500 focus:bg-white outline-none transition-all font-bold text-gray-800 placeholder-gray-400 uppercase tracking-widest text-center text-sm"
                              value={formData.captchaInput}
                              onChange={e => setFormData({...formData, captchaInput: e.target.value})}
                            />
                         </div>
                         <div 
                           onClick={generateCaptcha}
                           className="w-36 bg-[#F0F4F8] rounded-2xl flex items-center justify-center cursor-pointer select-none relative overflow-hidden group/captcha hover:ring-2 hover:ring-indigo-100 transition-all active:scale-95"
                           title="点击刷新验证码"
                        >
                            <div className="absolute inset-0 opacity-10 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-500 via-purple-500 to-transparent"></div>
                            {/* Noise Background */}
                            <div className="absolute inset-0 opacity-20" style={{backgroundImage: 'url("data:image/svg+xml,%3Csvg viewBox=\'0 0 200 200\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noiseFilter\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.65\' numOctaves=\'3\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noiseFilter)\' opacity=\'0.5\'/%3E%3C/svg%3E")'}}></div>

                            <span className="text-2xl font-mono font-black text-gray-600 tracking-[0.25em] relative z-10 transform -rotate-3 select-none drop-shadow-sm">
                               {captchaCode}
                            </span>

                            <div className="absolute top-2 right-2 text-indigo-400 opacity-0 group-hover/captcha:opacity-100 transition-opacity">
                               <RefreshCw size={12} />
                            </div>
                         </div>
                      </div>
                   </div>
                </div>
             )}

             {error && (
               <div className="bg-red-50 text-red-600 text-xs font-bold p-4 rounded-xl border border-red-100 flex items-center gap-2 animate-shake">
                 <AlertCircle size={16} className="shrink-0" />
                 {error}
               </div>
             )}

             <button
               type="submit"
               className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold text-lg hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 shadow-xl shadow-indigo-200 hover:shadow-indigo-300 hover:-translate-y-1 active:translate-y-0 active:scale-95 duration-200 mt-4 group"
             >
               {loginMode === 'STAFF' ? '验证并登录' : '管理员登录'} 
               <ArrowRight size={20} className="group-hover:translate-x-1 transition-transform" />
             </button>
          </form>

          {/* Test Accounts Hint (Chips Style) */}
          <div className="mt-8 pt-6 border-t border-dashed border-gray-200">
             <div className="text-[10px] font-bold text-center text-gray-400 uppercase tracking-widest mb-4">Development Accounts</div>
             <div className="flex flex-wrap justify-center gap-2">
                <button className="px-3 py-1.5 bg-gray-50 hover:bg-green-50 text-gray-500 hover:text-green-600 border border-gray-200 hover:border-green-200 rounded-lg text-xs font-medium transition-colors"
                   onClick={() => { setLoginMode('STAFF'); setFormData({...formData, name: '已签到员工', phone: '13800000001', idCardSuffix: '888888'}) }}
                >
                   已签到 (888888)
                </button>
                <button className="px-3 py-1.5 bg-gray-50 hover:bg-purple-50 text-gray-500 hover:text-purple-600 border border-gray-200 hover:border-purple-200 rounded-lg text-xs font-medium transition-colors"
                   onClick={() => { setLoginMode('STAFF'); setFormData({...formData, name: '赵云(组长)', phone: '13800000004', idCardSuffix: '111111'}) }}
                >
                   组长 (111111)
                </button>
                <button className="px-3 py-1.5 bg-gray-50 hover:bg-indigo-50 text-gray-500 hover:text-indigo-600 border border-gray-200 hover:border-indigo-200 rounded-lg text-xs font-medium transition-colors"
                   onClick={() => { setLoginMode('ADMIN'); setFormData({...formData, adminUser: 'admin', adminPass: 'password'}) }}
                >
                   管理员 (admin)
                </button>
             </div>
          </div>

        </div>
      </div>
    </div>
  );
};

export default Login;
]]></content>
</change>
